import{_ as t,a as e,b as s,c as o}from"./chunks/qBittorrent_test.Cy9qqu-v.js";import{_ as r,a as n,b as i}from"./chunks/aria2.DAOm4DfL.js";import{_ as l,c as d,o as p,ag as c}from"./chunks/framework.DPDPlp3K.js";const x=JSON.parse('{"title":"下载设置","description":"","frontmatter":{},"headers":[],"relativePath":"config/download.md","filePath":"config/download.md","lastUpdated":1741687494000}'),h={name:"config/download.md"};function m(b,a,u,q,g,f){return p(),d("div",null,a[0]||(a[0]=[c('<h1 id="下载设置" tabindex="-1">下载设置 <a class="header-anchor" href="#下载设置" aria-label="Permalink to &quot;下载设置&quot;">​</a></h1><img src="'+t+'" alt="download-screenshot" id="download-screenshot"><h2 id="下载工具" tabindex="-1">下载工具 <a class="header-anchor" href="#下载工具" aria-label="Permalink to &quot;下载工具&quot;">​</a></h2><div><img src="'+r+'" alt="transmission" width="60"><img src="'+n+'" alt="qbittorrent" width="60"><img src="'+i+'" alt="qbittorrent" width="60"></div><ul><li><code>ani-rss</code> 支持 <strong>Transmission</strong>、<strong>qBittorrent</strong>、<strong>Aria2</strong> 三种下载工具。</li><li>受 <code>api</code> 限制 <code>ani-rss</code>的支持情况如下</li></ul><div style="overflow-x:auto;"><div style="width:1000px;"><table tabindex="0"><thead><tr><th>名称</th><th>自动下载</th><th>下载时重命名</th><th>下载时复杂解构重命名</th><th>下载完成后重命名</th><th>做种时修改下载位置</th><th>下载完成通知</th><th>AList</th></tr></thead><tbody><tr><td>qBittorrent</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Transmission</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Aria2</td><td>✅</td><td>❌</td><td>❌</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr></tbody></table></div></div><p><em>（强烈推荐使用 <strong>qBittorrent</strong>）</em></p><details class="details custom-block"><summary>qBittorrent设置</summary><ol><li>在设置面板中打开WebUI并设置用户名和密码。</li></ol><p><img src="'+e+'" alt="qBittorrent设置" loading="lazy"></p><ol start="2"><li>在浏览器中打开 <code>http://localhost:8989</code> （注意将端口号改为与设置qBittorrent中一致）。不出意外的话应该能进入WebUI，登陆成功后应该能见到如下页面，说明<code>qBittorrent</code> 端设置无误。（如果无法打开页面，请重新检查<code>qBittorrent</code>的设置）</li></ol><p><img src="'+s+'" alt="qBittorrent页面" loading="lazy"></p><ol start="3"><li>在<code>ani-rss</code>中将上述的地址，用户名，密码填入后点击<code>测试</code>。</li></ol><p><img src="'+o+`" alt="qBittorrent测试" loading="lazy"></p><p>如果出现<code>登陆成功</code>则说明设置成功。</p></details><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><strong>使用 Aria2 时，必须让 ani-rss 与 Aria2 路径保持一致才能自动重命名 详见</strong> <a href="/config/basic.html#docker-mount">docker映射挂载</a></p></div><div class="info custom-block"><p class="custom-block-title">不支持下载时重命名会导致的问题</p><p>在视频文件未重命名时已经有 emby 生成视频缩略图 .nfo 元数据, 当重命名后还会再次生成一次。且重命名后的视频再次被刮削到时 emby 无法触发 Webhook 通知。</p><p>个人喜欢设置 <a href="https://emby.media/" target="_blank" rel="noreferrer">Emby</a> 的 Webhook 通知让 <a href="https://github.com/wushuo894/EmbyPinyin" target="_blank" rel="noreferrer">EmbyPinyin</a> 处理中文拼音首字母索引</p></div><h2 id="save-path" tabindex="-1">保存位置 <a class="header-anchor" href="#save-path" aria-label="Permalink to &quot;保存位置 {id=save-path}&quot;">​</a></h2><p>下载器的保存位置</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果为空则 <code>不会进行下载</code></p></div><h2 id="剧场版保存位置" tabindex="-1">剧场版保存位置 <a class="header-anchor" href="#剧场版保存位置" aria-label="Permalink to &quot;剧场版保存位置&quot;">​</a></h2><p>如果为空则使用 <a href="#save-path">保存位置</a></p><h2 id="auto-delete" tabindex="-1">自动删除 <a class="header-anchor" href="#auto-delete" aria-label="Permalink to &quot;自动删除 { id=auto-delete }&quot;">​</a></h2><p>自动删除已完成的任务, 不会删除本地文件</p><p>如果同时开启了 <a href="/config/basic.html#back-rss">备用rss</a> 将会自动删除对应洗版视频, 以实现 <code>主rss</code> 的替换</p><h3 id="等待做种完毕" tabindex="-1">等待做种完毕 <a class="header-anchor" href="#等待做种完毕" aria-label="Permalink to &quot;等待做种完毕&quot;">​</a></h3><p>等待做种完成后才会删除任务</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>推荐等待做种，否则可能被 <a href="https://github.com/PBH-BTN/PeerBanHelper" target="_blank" rel="noreferrer">PeerBanHelper</a> 标记为吸血</p></div><h3 id="仅在主rss更新后删除备用rss" tabindex="-1">仅在主RSS更新后删除备用RSS <a class="header-anchor" href="#仅在主rss更新后删除备用rss" aria-label="Permalink to &quot;仅在主RSS更新后删除备用RSS&quot;">​</a></h3><p>主RSS将 <code>不会自动删除</code>，仅在其更新后删除对应 <code>备用RSS</code> 的任务与文件</p><h2 id="拼音首字母" tabindex="-1">拼音首字母 <a class="header-anchor" href="#拼音首字母" aria-label="Permalink to &quot;拼音首字母&quot;">​</a></h2><p>用于整理番剧到 <code>A-Z</code> 文件夹中, 如一下结构:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>├── A</span></span>
<span class="line"><span>│   └── 安达与岛村</span></span>
<span class="line"><span>│       └── S01</span></span>
<span class="line"><span>│           ├── 安达与岛村 S01E01.mp4</span></span>
<span class="line"><span>│           ├── 安达与岛村 S01E02.mp4</span></span>
<span class="line"><span>│           ├── 安达与岛村 S01E03.mp4</span></span>
<span class="line"><span>│           └── 安达与岛村 S01E04.mp4</span></span>
<span class="line"><span>├── B</span></span>
<span class="line"><span>│   └── BanG Dream! It&#39;s MyGO!!!!!</span></span>
<span class="line"><span>│       └── S01</span></span>
<span class="line"><span>│           ├── BanG Dream! It&#39;s MyGO!!!!! S01E01.mp4</span></span>
<span class="line"><span>│           ├── BanG Dream! It&#39;s MyGO!!!!! S01E02.mp4</span></span>
<span class="line"><span>│           ├── BanG Dream! It&#39;s MyGO!!!!! S01E03.mp4</span></span></code></pre></div><h2 id="季度" tabindex="-1">季度 <a class="header-anchor" href="#季度" aria-label="Permalink to &quot;季度&quot;">​</a></h2><p>将番剧存放于 <code>yyyy-MM</code> 下 如 <code>2024-07</code></p><h2 id="同时下载限制" tabindex="-1">同时下载限制 <a class="header-anchor" href="#同时下载限制" aria-label="Permalink to &quot;同时下载限制&quot;">​</a></h2><p>防止同时下载任务过多导致 <strong>qBittorrent</strong> 卡死</p><p>强烈建议视性能设置, 推荐 <code>3-5</code></p><h2 id="延迟下载" tabindex="-1">延迟下载 <a class="header-anchor" href="#延迟下载" aria-label="Permalink to &quot;延迟下载&quot;">​</a></h2><p>主要用于需要同步到网盘的场景</p><p>一般30分钟后就支持秒传了</p><h2 id="检测是否死种" tabindex="-1">检测是否死种 <a class="header-anchor" href="#检测是否死种" aria-label="Permalink to &quot;检测是否死种&quot;">​</a></h2><p>RSS更新后添加下载任务时如果出现异常则会发送 <a href="/config/message.html">通知</a></p><h2 id="qbittorrent设置" tabindex="-1">qBittorrent设置 <a class="header-anchor" href="#qbittorrent设置" aria-label="Permalink to &quot;qBittorrent设置&quot;">​</a></h2><h3 id="分享率" tabindex="-1">分享率 <a class="header-anchor" href="#分享率" aria-label="Permalink to &quot;分享率&quot;">​</a></h3><p>&quot;-1&quot;表示禁用, &quot;-2&quot;使用全局设置</p><h3 id="总做种时长" tabindex="-1">总做种时长 <a class="header-anchor" href="#总做种时长" aria-label="Permalink to &quot;总做种时长&quot;">​</a></h3><p>&quot;-1&quot;表示禁用, &quot;-2&quot;使用全局设置</p><h3 id="非活跃时长" tabindex="-1">非活跃时长 <a class="header-anchor" href="#非活跃时长" aria-label="Permalink to &quot;非活跃时长&quot;">​</a></h3><p>&quot;-1&quot;表示禁用, &quot;-2&quot;使用全局设置</p><h3 id="qb保存路径" tabindex="-1">qb保存路径 <a class="header-anchor" href="#qb保存路径" aria-label="Permalink to &quot;qb保存路径&quot;">​</a></h3><p>开启后将使用qBittorrent的保存路径配置 <strong>(下载路径不受影响)</strong></p><h2 id="alist" tabindex="-1">Alist <a class="header-anchor" href="#alist" aria-label="Permalink to &quot;Alist&quot;">​</a></h2><p>自动将下载完成的文件上传至 <code>alist</code></p><h3 id="alisthost" tabindex="-1">AlistHost <a class="header-anchor" href="#alisthost" aria-label="Permalink to &quot;AlistHost&quot;">​</a></h3><p><code>alist</code> 的 <code>http</code> 地址</p><h3 id="alisttoken" tabindex="-1">AlistToken <a class="header-anchor" href="#alisttoken" aria-label="Permalink to &quot;AlistToken&quot;">​</a></h3><p>令牌, 可在 <code>alist网页 -&gt; 管理 -&gt; 设置 -&gt; 其他 -&gt; 令牌</code> 找到</p><h3 id="alistpath" tabindex="-1">AlistPath <a class="header-anchor" href="#alistpath" aria-label="Permalink to &quot;AlistPath&quot;">​</a></h3><p>上传位置</p>`,53)]))}const S=l(h,[["render",m]]);export{x as __pageData,S as default};
